const path = require('path');
const fs = require('fs');
const body = $input.item.json.body || $input.item.json;
const baseDir = process.env.FRAMES_BASE_PATH || '/data/frames';
const dir = path.join(baseDir, String(body.listing_id));
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
const fileName = (body.frame_name || `frame_${String(body.frame_number).padStart(4, '0')}`) + '.png';
const filePath = path.join(dir, fileName);
fs.writeFileSync(filePath, Buffer.from(body.image_base64, 'base64'));
return [{ json: { saved: filePath, frame_number: body.frame_number, total_frames: body.total_frames, listing_id: body.listing_id, frame_name: fileName } }];
